Certainly! Setting up a clean and modular Terraform layout is crucial for maintaining scalability, readability, and reusability in your infrastructure as code (IaC) projects. Below is an example of how you might structure your Terraform files for AWS networking, EKS, and shared security controls.

### Directory Structure

```
terraform-aws-platform/
├── main.tf
├── variables.tf
├── outputs.tf
└── modules/
    ├── vpc/
    │   ├── main.tf
    │   ├── variables.tf
    │   └── outputs.tf
    ├── eks-cluster/
    │   ├── main.tf
    │   ├── variables.tf
    │   └── outputs.tf
    ├── security-group/
    │   ├── main.tf
    │   ├── variables.tf
    │   └── outputs.tf
```

### `main.tf`
This file will call the modules and pass necessary variables.

```hcl
provider "aws" {
  region = var.aws_region
}

module "vpc" {
  source              = "./modules/vpc"
  cidr_block          = var.vpc_cidr_block
  az_count            = var.az_count
  public_subnets      = var.public_subnets
  private_subnets     = var.private_subnets
  enable_nat_gateway  = true
}

module "eks_cluster" {
  source              = "./modules/eks-cluster"
  vpc_id              = module.vpc.vpc_id
  subnet_ids          = module.vpc.public_subnet_ids
  cluster_name        = var.eks_cluster_name
  node_group_name     = var.node_group_name
  desired_size        = var.desired_size
}

module "security_group" {
  source              = "./modules/security-group"
  vpc_id              = module.vpc.vpc_id
}
```

### `variables.tf`
Define all the variables used in your Terraform configuration.

```hcl
variable "aws_region" {
  description = "The AWS region to deploy resources."
}

variable "vpc_cidr_block" {
  description = "CIDR block for VPC."
}

variable "az_count" {
  description = "Number of availability zones to use."
}

variable "public_subnets" {
  description = "List of public subnets."
}

variable "private_subnets" {
  description = "List of private subnets."
}

variable "eks_cluster_name" {
  description = "Name for the EKS cluster."
}

variable "node_group_name" {
  description = "Name for the node group in the EKS cluster."
}

variable "desired_size" {
  description = "Desired size of the worker nodes in the EKS cluster."
}
```

### `outputs.tf`
Define outputs that you want to expose.

```hcl
output "vpc_id" {
  value = module.vpc.vpc_id
}

output "eks_cluster_endpoint" {
  value = module.eks_cluster.cluster_endpoint
}

output "security_group_id" {
  value = module.security_group.security_group_id
}
```

### `modules/vpc/main.tf`
Define the VPC and subnets.

```hcl
resource "aws_vpc" "main" {
  cidr_block           = var.cidr_block
  enable_dns_hostnames = true
}

resource "aws_subnet" "public" {
  count                = length(var.public_subnets)
  vpc_id               = aws_vpc.main.id
  cidr_block           = element(var.public_subnets, count.index)
  availability_zone    = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = true
}

resource "aws_subnet" "private" {
  count                = length(var.private_subnets)
  vpc_id               = aws_vpc.main.id
  cidr_block           = element(var.private_subnets, count.index)
  availability_zone    = element(data.aws_availability_zones.available.names, count.index)
}
```

### `modules/vpc/variables.tf`
Define variables for the VPC module.

```hcl
variable "cidr_block" {
  description = "CIDR block for VPC."
}

variable "az_count" {
  description = "Number of availability zones to use."
}

variable "public_subnets" {
  description = "List of public subnets."
}

variable "private_subnets" {
  description = "List of private subnets."
}
```

### `modules/vpc/outputs.tf`
Define outputs for the VPC module.

```hcl
output "vpc_id" {
  value = aws_vpc.main.id
}

output "public_subnet_ids" {
  value = aws_subnet.public.*.id
}

output "private_subnet_ids" {
  value = aws_subnet.private.*.id
}
```

### `modules/eks-cluster/main.tf`
Define the EKS cluster and node group.

```hcl
resource "aws_eks_cluster" "main" {
  name     = var.cluster_name
  role_arn = data.aws_iam_role.eks.arn
  vpc_config {
    subnet_ids = var.subnet_ids
  }
}

data "aws_iam_role" "eks" {
  name = "${var.cluster_name}-cluster"
}
```

### `modules/eks-cluster/variables.tf`
Define variables for the EKS module.

```hcl
variable "vpc_id" {
  description = "ID of the VPC."
}

variable "subnet_ids" {
  description = "List of subnet IDs."
}

variable "cluster_name" {
  description = "Name for the EKS cluster."
}

variable "node_group_name" {
  description = "Name for the node group in the EKS cluster."
}

variable "desired_size" {
  description = "Desired size of the worker nodes in the EKS cluster."
}
```

### `modules/security-group/main.tf`
Define a security group.

```hcl
resource "aws_security_group" "main" {
  name        = var.name
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

output "security_group_id" {
  value = aws_security_group.main.id
}
```

### `modules/security-group/variables.tf`
Define variables for the security group module.

```hcl
variable "name" {
  description = "Name of the security group."
}

variable "vpc_id" {
  description = "ID of the VPC."
}
```

